input.content:
.hamster-page {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 2rem;
  gap: 2rem;
}

.hamster-card {
  display: flex;
  align-items: flex-start;
  gap: 2.5rem;
  background: #fff;
  border-radius: 20px;
  padding: 2.5rem;
  max-width: 750px;
  width: 100%;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.08);
}

.hamster-photo-wrapper {
  flex-shrink: 0;
}

.hamster-photo {
  width: 200px;
  height: 200px;
  border-radius: 50%;
  object-fit: cover;
  border: 4px solid #f0e6d3;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.1);
}

.hamster-info {
  flex: 1;
  min-width: 0;
}

.hamster-name {
  font-size: 2rem;
  font-weight: 700;
  color: #6b4226;
  margin-bottom: 1rem;
}

.hamster-details {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.75rem;
  margin-bottom: 1.25rem;
}

.hamster-detail {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.detail-label {
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: #b8947a;
}

.detail-value {
  font-size: 1.05rem;
  color: #4a3728;
  font-weight: 500;
}

.hamster-bio {
  font-size: 1rem;
  line-height: 1.7;
  color: #6b5a4e;
  font-style: italic;
}

.visit-another-btn {
  padding: 0.85rem 2.5rem;
  font-size: 1.1rem;
  font-weight: 600;
  color: #fff;
  background: linear-gradient(135deg, #c8925a, #a0724a);
  border: none;
  border-radius: 12px;
  transition: transform 0.2s, box-shadow 0.2s;
  box-shadow: 0 4px 16px rgba(160, 114, 74, 0.3);
}

.visit-another-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 24px rgba(160, 114, 74, 0.4);
}

.visit-another-btn:active {
  transform: translateY(0);
}

/* Mobile: stack vertically */
@media (max-width: 768px) {
  .hamster-page {
    padding: 1rem;
    gap: 1.5rem;
  }

  .hamster-card {
    flex-direction: column;
    align-items: center;
    text-align: center;
    padding: 1.5rem;
    gap: 1.5rem;
  }

  .hamster-photo {
    width: 160px;
    height: 160px;
  }

  .hamster-name {
    font-size: 1.6rem;
  }

  .hamster-details {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hamster-bio {
    text-align: center;
  }

  .visit-another-btn {
    width: 100%;
    max-width: 400px;
  }
}

