import('./src/data/hamsters.js').then(m => {
  const h = m.default;
  const map = {'Gluttonous 🍽️':15,'Shy 😳':5,'Energetic ⚡':12,'Chill 😌':8,'Chaotic 💫':15,'Picky 🤔':4,'Friendly 🥰':12};
  const foodIds = ['sunflower-seeds','strawberries','broccoli','carrots','apples','sweet-corn','peanuts','blueberries','sweet-potato','cinnamon-oats','cucumber','banana-chips'];

  let ok = true;
  if (h.length !== 12) { console.log('F1 FAIL: hamster count'); ok = false; }
  if (!h.every(x => x.moodBoost === map[x.personality])) { console.log('F1 FAIL: moodBoost'); ok = false; }
  if (!h.every(x => foodIds.includes(x.favouriteFood))) { console.log('F1 FAIL: food ids'); ok = false; }
  if (!h.every(x => x.image === '/hamsters/' + x.name + '.jpg')) { console.log('F1 FAIL: image paths'); ok = false; }
  const fields = ['name','age','personality','favouriteFood','hobby','bio','image','catchphrase','moodBoost'];
  if (!h.every(x => fields.every(f => f in x))) { console.log('F1 FAIL: fields'); ok = false; }
  if (ok) console.log('F1 regression: PASS');
})

// === F2: fallback chat ===
import('./src/utils/chatFallback.js').then(m => {
  const hamster = {name:'Testy',favouriteFood:'carrots',catchphrase:'Whee!',hobby:'running',personality:'Chill 😌'};

  // Priority: food > play > mood > greeting > default
  const r1 = m.getFallbackResponse('I am hungry', hamster);
  if (!r1.includes('loves')) console.log('FAIL: food intent not matched');

  const r2 = m.getFallbackResponse('let us play!', hamster);
  if (!r2.includes('spent all morning')) console.log('FAIL: play intent not matched');

  const r3 = m.getFallbackResponse('how are you feeling', hamster);
  if (!r3.includes('is feeling')) console.log('FAIL: mood intent not matched');

  const r4 = m.getFallbackResponse('hello there!', hamster);
  if (!r4.includes('missed you')) console.log('FAIL: greeting intent not matched');

  const r5 = m.getFallbackResponse('xyzzy nothing matches', hamster);
  if (!r5.includes('is busy')) console.log('FAIL: default intent not matched');

  // Case-insensitive
  const r6 = m.getFallbackResponse('HUNGRY', hamster);
